import{_ as i,c as s,o as t,a2 as a}from"./chunks/framework.CIiVzG-O.js";const m=JSON.parse('{"title":"macOS Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/permissions.md","filePath":"guide/permissions.md","lastUpdated":1781417556000}'),n={name:"guide/permissions.md"};function o(r,e,l,p,c,d){return t(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="macos-permissions" tabindex="-1">macOS Permissions <a class="header-anchor" href="#macos-permissions" aria-label="Permalink to &quot;macOS Permissions&quot;">​</a></h1><p>PetReminder may request a few macOS permissions to provide the best experience. This page explains what each permission is for and how to manage them.</p><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>When a reminder fires, PetReminder displays a notification. macOS will prompt you to allow notifications the first time a reminder triggers.</p><p><strong>What it&#39;s used for</strong>: Showing reminder alerts and pet appearance notifications.</p><p><strong>Manage</strong>: System Settings → <strong>Notifications</strong> → <strong>PetReminder</strong></p><p>You can customize:</p><ul><li>Alert style (banners, alerts, or none)</li><li>Show on lock screen</li><li>Show in Notification Center</li><li>Sound</li></ul><h2 id="files-and-folders" tabindex="-1">Files and Folders <a class="header-anchor" href="#files-and-folders" aria-label="Permalink to &quot;Files and Folders&quot;">​</a></h2><p>PetReminder stores your reminders, settings, and downloaded pet data locally.</p><p><strong>What it&#39;s used for</strong>: Saving reminder data on your Mac and storing purchased pet files.</p><p><strong>Manage</strong>: System Settings → <strong>Privacy &amp; Security</strong> → <strong>Files and Folders</strong></p><p>Grant access when prompted during first launch for the best experience.</p><h2 id="accessibility-optional" tabindex="-1">Accessibility (Optional) <a class="header-anchor" href="#accessibility-optional" aria-label="Permalink to &quot;Accessibility (Optional)&quot;">​</a></h2><p>Some pet interaction features may request Accessibility permission in future updates (for example, click-through pet behavior).</p><p><strong>What it&#39;s used for</strong>: Allowing pets to receive mouse events on your desktop.</p><p><strong>Manage</strong>: System Settings → <strong>Privacy &amp; Security</strong> → <strong>Accessibility</strong></p><p>This permission is optional and only needed if you enable related features.</p><h2 id="resetting-a-permission-with-terminal" tabindex="-1">Resetting a Permission with Terminal <a class="header-anchor" href="#resetting-a-permission-with-terminal" aria-label="Permalink to &quot;Resetting a Permission with Terminal&quot;">​</a></h2><p>If a permission dialog was dismissed or the state is inconsistent, you can reset macOS permission prompts using <code>tccutil</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Reset Notifications prompts for PetReminder</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Accessibility</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> com.w3cub.reminder</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># To see what was reset</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> All</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> com.w3cub.reminder</span></span></code></pre></div><p>After running <code>tccutil</code>, restart the app and trigger the feature again to be reprompted.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li>If pets don&#39;t appear on reminders, check <strong>Notifications</strong> permission is granted.</li><li>If purchased pets aren&#39;t downloading, check <strong>Files and Folders</strong> permission.</li><li>After changing permissions, always quit and reopen PetReminder for changes to take effect.</li></ul><p>For more help, visit the <a href="./troubleshooting.html">Troubleshooting guide</a>.</p>`,25)])])}const g=i(n,[["render",o]]);export{m as __pageData,g as default};
